using System.ComponentModel;
using System.Net.Http.Json;
using System.Text;
using System.Text.Json.Serialization;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Provides AI-callable tools for web search and note-taking used by the research agent.
/// </summary>
public sealed class ResearchTools
{
    private readonly HttpClient _httpClient;
    private readonly ILogger<ResearchTools> _logger;
    private readonly List<NoteEntry> _notes = [];

    public ResearchTools(HttpClient httpClient, ILogger<ResearchTools> logger)
    {
        _httpClient = httpClient;
        _logger = logger;
    }

    public IReadOnlyList<NoteEntry> Notes => _notes;

    /// <summary>
    /// Creates the list of AI tools exposed to the agent.
    /// </summary>
    public IList<AITool> CreateTools() =>
    [
        AIFunctionFactory.Create(SearchWebAsync, nameof(SearchWebAsync), "Searches the web for the given query and returns a list of result snippets. Use this to find information about a topic."),
        AIFunctionFactory.Create(AddNote, nameof(AddNote), "Saves a research note with a title and body. Use this to record key findings during research."),
        AIFunctionFactory.Create(GetNotes, nameof(GetNotes), "Returns all notes taken so far. Use this to review what has been recorded before writing a summary."),
    ];

    [Description("Searches the web for the given query and returns a list of result snippets.")]
    private async Task<string> SearchWebAsync(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        _logger.LogInformation("  🔍 Searching: {Query}", query);

        try
        {
            var encodedQuery = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetFromJsonAsync<DuckDuckGoResponse>(url, cancellationToken);
            if (response is null)
            {
                return "No results found.";
            }

            var sb = new StringBuilder();

            if (!string.IsNullOrWhiteSpace(response.AbstractText))
            {
                sb.AppendLine($"## Summary\n{response.AbstractText}\nSource: {response.AbstractUrl}\n");
            }

            if (response.RelatedTopics is { Count: > 0 })
            {
                sb.AppendLine("## Related Topics");
                foreach (var topic in response.RelatedTopics.Take(5))
                {
                    if (!string.IsNullOrWhiteSpace(topic.Text))
                    {
                        sb.AppendLine($"- {topic.Text}");
                        if (!string.IsNullOrWhiteSpace(topic.FirstUrl))
                        {
                            sb.AppendLine($"  Source: {topic.FirstUrl}");
                        }
                    }
                }
            }

            var result = sb.ToString();
            return string.IsNullOrWhiteSpace(result) ? "No relevant results found for this query." : result;
        }
        catch (Exception ex)
        {
            _logger.LogWarning(ex, "Web search failed for query: {Query}", query);
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Saves a research note with a title and body.")]
    private string AddNote(
        [Description("Short title for the note")] string title,
        [Description("The note content with key findings")] string body)
    {
        _notes.Add(new NoteEntry(title, body, DateTime.UtcNow));
        _logger.LogInformation("  📝 Note added: {Title}", title);
        return $"Note '{title}' saved. You now have {_notes.Count} note(s).";
    }

    [Description("Returns all notes taken so far.")]
    private string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            sb.AppendLine($"### Note {i + 1}: {note.Title}");
            sb.AppendLine(note.Body);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

public sealed record NoteEntry(string Title, string Body, DateTime CreatedAt);

