    var researchTools = sp.GetRequiredService<ResearchTools>();

    return chatClient.AsAIAgent(
        name: "ResearchAgent",
        description: "An AI agent that researches a topic by searching the web and taking notes, then produces a summary.",
        instructions: """
            You are a thorough research assistant. When given a topic:
            1. Search the web multiple times with different queries to gather diverse information.
            2. After each search, save key findings as notes using the AddNote tool.
            3. Once you have gathered enough information (at least 3 searches), review your notes with GetNotes.
            4. Finally, write a comprehensive summary of your findings, citing the sources where possible.
            Be systematic and thorough. Always take notes before summarizing.
            """,
        tools: researchTools.CreateTools());
});

using var host = builder.Build();

var agent = host.Services.GetRequiredService<ChatClientAgent>();
var logger = host.Services.GetRequiredService<ILogger<Program>>();

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔬 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

try
{
    var response = await agent.RunAsync(
        $"Research the following topic and provide a comprehensive summary: {topic}",
        session,
        runOptions);

    Console.WriteLine("\n══════════════════════════════════════════");
    Console.WriteLine("📋 RESEARCH SUMMARY");
    Console.WriteLine("══════════════════════════════════════════\n");
    Console.WriteLine(response.Text);

    var researchTools = host.Services.GetRequiredService<ResearchTools>();
    if (researchTools.Notes.Count > 0)
    {
        Console.WriteLine($"\n📝 {researchTools.Notes.Count} note(s) were taken during research.");
    }

    if (response.Usage is { } usage)
    {
        logger.LogDebug("Token usage — Input: {Input}, Output: {Output}",
            usage.InputTokenCount, usage.OutputTokenCount);
    }
}
catch (Exception ex)
{
    logger.LogError(ex, "Research agent failed");
    Console.WriteLine($"\n❌ Error: {ex.Message}");
    return 1;
}

return 0;

