1. using System.ComponentModel;
2. using System.Net.Http.Json;
3. using System.Text;
4. using System.Text.Json.Serialization;
5. using Microsoft.Extensions.AI;
6. using Microsoft.Extensions.Logging;
7. 
8. namespace ResearchAgent;
9. 
10. /// <summary>
11. /// Provides AI-callable tools for web search and note-taking used by the research agent.
12. /// </summary>
13. public sealed class ResearchTools
14. {
15.     private readonly HttpClient _httpClient;
16.     private readonly ILogger<ResearchTools> _logger;
17.     private readonly List<NoteEntry> _notes = [];
18. 
19.     public ResearchTools(HttpClient httpClient, ILogger<ResearchTools> logger)
20.     {
21.         _httpClient = httpClient;
22.         _logger = logger;
23.     }
24. 
25.     public IReadOnlyList<NoteEntry> Notes => _notes;
26. 
27.     /// <summary>
28.     /// Creates the list of AI tools exposed to the agent.
29.     /// </summary>
30.     public IList<AITool> CreateTools() =>
31.     [
32.         AIFunctionFactory.Create(SearchWebAsync, nameof(SearchWebAsync), "Searches the web for the given query and returns a list of result snippets. Use this to find information about a topic."),
33.         AIFunctionFactory.Create(AddNote, nameof(AddNote), "Saves a research note with a title and body. Use this to record key findings during research."),
34.         AIFunctionFactory.Create(GetNotes, nameof(GetNotes), "Returns all notes taken so far. Use this to review what has been recorded before writing a summary."),
35.     ];
36. 
37.     [Description("Searches the web for the given query and returns a list of result snippets.")]
38.     private async Task<string> SearchWebAsync(
39.         [Description("The search query string")] string query,
40.         CancellationToken cancellationToken = default)
41.     {
42.         _logger.LogInformation("  🔍 Searching: {Query}", query);
43. 
44.         try
45.         {
46.             var encodedQuery = Uri.EscapeDataString(query);
47.             var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";
48. 
49.             var response = await _httpClient.GetFromJsonAsync<DuckDuckGoResponse>(url, cancellationToken);
50.             if (response is null)
51.             {
52.                 return "No results found.";
53.             }
54. 
55.             var sb = new StringBuilder();
56. 
57.             if (!string.IsNullOrWhiteSpace(response.AbstractText))
58.             {
59.                 sb.AppendLine($"## Summary\n{response.AbstractText}\nSource: {response.AbstractUrl}\n");
60.             }
61. 
62.             if (response.RelatedTopics is { Count: > 0 })
63.             {
64.                 sb.AppendLine("## Related Topics");
65.                 foreach (var topic in response.RelatedTopics.Take(5))
66.                 {
67.                     if (!string.IsNullOrWhiteSpace(topic.Text))
68.                     {
69.                         sb.AppendLine($"- {topic.Text}");
70.                         if (!string.IsNullOrWhiteSpace(topic.FirstUrl))
71.                         {
72.                             sb.AppendLine($"  Source: {topic.FirstUrl}");
73.                         }
74.                     }
75.                 }
76.             }
77. 
78.             var result = sb.ToString();
79.             return string.IsNullOrWhiteSpace(result) ? "No relevant results found for this query." : result;
80.         }
81.         catch (Exception ex)
82.         {
83.             _logger.LogWarning(ex, "Web search failed for query: {Query}", query);
84.             return $"Search failed: {ex.Message}";
85.         }
86.     }
87. 
88.     [Description("Saves a research note with a title and body.")]
89.     private string AddNote(
90.         [Description("Short title for the note")] string title,
91.         [Description("The note content with key findings")] string body)
92.     {
93.         _notes.Add(new NoteEntry(title, body, DateTime.UtcNow));
94.         _logger.LogInformation("  📝 Note added: {Title}", title);
95.         return $"Note '{title}' saved. You now have {_notes.Count} note(s).";
96.     }
97. 
98.     [Description("Returns all notes taken so far.")]
99.     private string GetNotes()
100.     {
101.         if (_notes.Count == 0)
102.         {
103.             return "No notes have been taken yet.";
104.         }
105. 
106.         var sb = new StringBuilder();
107.         for (var i = 0; i < _notes.Count; i++)
108.         {
109.             var note = _notes[i];
110.             sb.AppendLine($"### Note {i + 1}: {note.Title}");
111.             sb.AppendLine(note.Body);
112.             sb.AppendLine();
113.         }
114. 
115.         return sb.ToString();
116.     }
117. }
118. 
119. public sealed record NoteEntry(string Title, string Body, DateTime CreatedAt);
120. 
121. file sealed class DuckDuckGoResponse
122. {
123.     [JsonPropertyName("AbstractText")]
124.     public string? AbstractText { get; set; }
125. 
126.     [JsonPropertyName("AbstractURL")]
127.     public string? AbstractUrl { get; set; }
128. 
129.     [JsonPropertyName("RelatedTopics")]
130.     public List<DuckDuckGoTopic>? RelatedTopics { get; set; }
131. }
132. 
133. file sealed class DuckDuckGoTopic
134. {
135.     [JsonPropertyName("Text")]
136.     public string? Text { get; set; }
137. 
138.     [JsonPropertyName("FirstURL")]
139.     public string? FirstUrl { get; set; }
140. }
